#include <iostream>

namespace geometry
{
    int rectPerimeter(int w, int h)
    {
        return 2 * (w + h);
    }
}

int main()
{
    int w {};
    int h {};
    std::cin >> w >> h;

    std::cout << "Perimeter: " << geometry::rectPerimeter(w, h) << '\n';
    return 0;
}

